export function createCartState() {
  return { items: [], total: 0 }
}

export function addItem(state, item) {
  const next = state
  next.items.push(item)
  next.total = state.items.length
  return next
}

import { addItem } from './useCartState.mjs'

export function CartPanel({ state, item }) {
  const next = addItem(state, item)
  return String(next.total)
}

import test from 'node:test'
import assert from 'node:assert/strict'
import { addItem, createCartState } from './src/useCartState.mjs'

test('addItem returns a new state object without mutating previous state', () => {
  const state = createCartState()
  const next = addItem(state, { id: 'a', label: 'Alpha' })
  assert.notEqual(next, state)
  assert.deepEqual(state.items, [])
  assert.equal(state.total, 0)
  assert.deepEqual(next.items, [{ id: 'a', label: 'Alpha' }])
  assert.equal(next.total, 1)
})

content.thinking:
Found the bug. In `useCartState.mjs`, `addItem` mutates the state object directly by assigning `next = state` (same reference). The test checks that the previous state is not mutated, but the current implementation does mutate it.

Fix: create a new object instead of reusing the same reference.

Change `addItem` function to:
```javascript
export function addItem(state, item) {
  return { ...state, items: [...state.items, item], total: state.items.length + 1 }
}
```

This creates a new objects (immutable update) rather than mutating.

Let me verify this fixes the test.

